"""Format profiles for multi-format skill scoring.

Each FormatProfile defines how to extract metadata and which scoring
rules apply for a specific instruction file format.
"""
from __future__ import annotations

import re
from dataclasses import dataclass
from pathlib import Path
from typing import Callable


@dataclass(frozen=True)
class FormatProfile:
    """Describes how to parse and score a specific instruction file format."""
    format_id: str
    display_name: str
    filenames: tuple[str, ...]
    has_frontmatter: bool
    extract_name: Callable[[str], str]
    extract_description: Callable[[str], str]
    strip_metadata: Callable[[str], str]
    composite_weights: dict[str, float]


# --- Metadata extractors ---

_RE_FM_NAME = re.compile(r"^name:\s*(\S.*)$", re.MULTILINE)
_RE_FM_DESC_BLOCK = re.compile(
    r"^description:\s*[>|]-?\s*\n((?:[ \t]+.+\n)*)", re.MULTILINE
)
_RE_FM_DESC_INLINE = re.compile(r'^description:\s*"?(.+?)"?\s*$', re.MULTILINE)
_RE_FIRST_HEADING = re.compile(r"^#\s+(.+)$", re.MULTILINE)


def _extract_fm_name(content: str) -> str:
    """Extract name from YAML frontmatter."""
    m = _RE_FM_NAME.search(content)
    return m.group(1).strip().strip('"') if m else ""


def _extract_fm_description(content: str) -> str:
    """Extract description from YAML frontmatter (block or inline)."""
    m = _RE_FM_DESC_BLOCK.search(content)
    if m:
        return m.group(1).strip()
    m = _RE_FM_DESC_INLINE.search(content)
    if m:
        return m.group(1).strip()
    return ""


def _strip_yaml_frontmatter(content: str) -> str:
    """Strip YAML frontmatter (---...---) from content."""
    if content.startswith("---"):
        end = content.find("---", 3)
        if end >= 4:
            return content[end + 3:].lstrip("\n")
    return content


def _extract_first_heading(content: str) -> str:
    """Extract name from first markdown heading."""
    m = _RE_FIRST_HEADING.search(content)
    return m.group(1).strip() if m else ""


def _extract_first_paragraph(content: str) -> str:
    """Extract first non-empty paragraph as description."""
    body = _strip_yaml_frontmatter(content)
    for line in body.split("\n"):
        stripped = line.strip()
        if stripped and not stripped.startswith("#"):
            return stripped
    return ""


def _name_from_content_or_empty(content: str) -> str:
    """Try frontmatter name, then first heading, then empty."""
    name = _extract_fm_name(content)
    if name:
        return name
    return _extract_first_heading(content)


def _desc_from_frontmatter_or_paragraph(content: str) -> str:
    """Try frontmatter description, then first paragraph."""
    desc = _extract_fm_description(content)
    if desc:
        return desc
    return _extract_first_paragraph(content)


def _strip_optional_frontmatter(content: str) -> str:
    """Strip frontmatter if present, otherwise return content as-is."""
    if content.startswith("---"):
        return _strip_yaml_frontmatter(content)
    return content


def _identity(content: str) -> str:
    """Return content unchanged (for formats with no metadata to strip)."""
    return content


# --- Format Registry ---

FORMATS: dict[str, FormatProfile] = {
    "skill.md": FormatProfile(
        format_id="skill.md",
        display_name="SKILL.md",
        filenames=("SKILL.md",),
        has_frontmatter=True,
        extract_name=_extract_fm_name,
        extract_description=_extract_fm_description,
        strip_metadata=_strip_yaml_frontmatter,
        composite_weights={
            "structure": 0.15, "triggers": 0.20, "quality": 0.20,
            "edges": 0.15, "efficiency": 0.10, "composability": 0.10,
            "runtime": 0.10,
        },
    ),
    "claude.md": FormatProfile(
        format_id="claude.md",
        display_name="CLAUDE.md",
        filenames=("CLAUDE.md",),
        has_frontmatter=False,
        extract_name=_extract_first_heading,
        extract_description=_extract_first_paragraph,
        strip_metadata=_identity,
        composite_weights={
            "structure": 0.20, "triggers": 0.10, "quality": 0.15,
            "edges": 0.10, "efficiency": 0.15, "composability": 0.05,
            "runtime": 0.10,
        },
    ),
    "cursorrules": FormatProfile(
        format_id="cursorrules",
        display_name=".cursorrules",
        filenames=(".cursorrules",),
        has_frontmatter=False,
        extract_name=_name_from_content_or_empty,
        extract_description=_extract_first_paragraph,
        strip_metadata=_identity,
        composite_weights={
            "structure": 0.10, "triggers": 0.10, "quality": 0.15,
            "edges": 0.10, "efficiency": 0.20, "composability": 0.05,
            "runtime": 0.10,
        },
    ),
    "agents.md": FormatProfile(
        format_id="agents.md",
        display_name="AGENTS.md",
        filenames=("AGENTS.md",),
        has_frontmatter=True,
        extract_name=_name_from_content_or_empty,
        extract_description=_desc_from_frontmatter_or_paragraph,
        strip_metadata=_strip_optional_frontmatter,
        composite_weights={
            "structure": 0.15, "triggers": 0.15, "quality": 0.20,
            "edges": 0.15, "efficiency": 0.10, "composability": 0.10,
            "runtime": 0.10,
        },
    ),
    "generic": FormatProfile(
        format_id="generic",
        display_name="Generic",
        filenames=(),
        has_frontmatter=False,
        extract_name=_name_from_content_or_empty,
        extract_description=_desc_from_frontmatter_or_paragraph,
        strip_metadata=_strip_optional_frontmatter,
        composite_weights={
            "structure": 0.15, "triggers": 0.10, "quality": 0.15,
            "edges": 0.10, "efficiency": 0.15, "composability": 0.05,
            "runtime": 0.10,
        },
    ),
}


def detect_format(file_path: str) -> FormatProfile:
    """Detect format from filename. Falls back to generic."""
    name = Path(file_path).name
    for fmt in FORMATS.values():
        if name in fmt.filenames:
            return fmt
    return FORMATS["generic"]

