import urllib.request, urllib.parse, tempfile

ALLOWED_HOSTS = {'raw.githubusercontent.com', 'github.com', 'gist.githubusercontent.com'}
MAX_REMOTE_SIZE = 500_000

def _fetch_remote_skill(url: str) -> str:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme != 'https':
        raise ValueError('Only HTTPS URLs supported')
    if parsed.hostname not in ALLOWED_HOSTS:
        raise ValueError(f'Host not allowed: {parsed.hostname}')
    # Convert github.com blob URLs to raw URLs
    raw_url = _github_to_raw(url)
    req = urllib.request.Request(raw_url, headers={'User-Agent': 'schliff'})
    with urllib.request.urlopen(req, timeout=10) as resp:
        content = resp.read(MAX_REMOTE_SIZE + 1)
        if len(content) > MAX_REMOTE_SIZE:
            raise ValueError(f'Remote file exceeds {MAX_REMOTE_SIZE} bytes')
        return content.decode('utf-8', errors='replace')
